-- Chien -> humain, Fête, Volume 1

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Aujourd''hui c''est ta fête. Je sais pas exactement ce que ça veut dire.',$$Aujourd''hui c''est ta fête. Je sais pas exactement ce que ça veut dire.
On m''a pas expliqué la différence avec l''anniversaire. Y''a pas de gâteau apparent. Pas de bougies. Juste toi qui sembles attendre quelque chose. J''ai décidé de faire comme si c''était aussi important que Noël. J''ai sauté partout pendant vingt minutes pour marquer le coup. C''était ma façon. Joyeuse fête, mon humain préféré, événement que je fête sans en comprendre les règles.
Avec enthousiasme non éclairé mais sincère, — {prenom}, ton animal qui fête tout avec la même intensité 🎉$$,'humorous',true,false,'nameday','chien','from'),

(null,'J''ai entendu quelqu''un dire ton prénom aujourd''hui. Plusieurs fois.',$$J''ai entendu quelqu''un dire ton prénom aujourd''hui. Plusieurs fois.
Au téléphone. Avec une voix joyeuse. Puis une autre personne a dit ton prénom. Puis une autre. Tout le monde disait ton prénom aujourd''hui et personne m''a expliqué pourquoi. J''ai aboyé à chaque fois pour signaler ma présence. C''était ma contribution. Joyeuse fête, mon humain préféré, dont le prénom résonnait partout ce matin.
Avec vigilance phonétique et participation vocale assumée, — {prenom}, ton animal gardien de ton prénom 📣$$,'humorous',true,false,'nameday','chien','from'),

(null,'Je sais pas ce qu''est une fête du prénom mais j''ai fait semblant de savoir.',$$Je sais pas ce qu''est une fête du prénom mais j''ai fait semblant de savoir.
Quand les gens sont venus te féliciter j''ai remué la queue comme si j''étais au courant depuis le début. J''avais l''air informé. Impliqué. En vérité j''attendais juste qu''on me remarque. Ça a marché. Joyeuse fête, mon humain préféré, dont les événements sont aussi les miens par extension.
Avec improvisation sociale parfaite et queue en mode automatique, — {prenom}, ton animal qui s''adapte à toutes les situations 🎭$$,'humorous',true,false,'nameday','chien','from'),

(null,'On m''a dit que ta fête c''est le jour du saint qui porte ton prénom.',$$On m''a dit que ta fête c''est le jour du saint qui porte ton prénom.
J''ai cherché si les chiens avaient un saint patron. Il paraît que c''est saint Roch. Je connais pas saint Roch. Mais si un jour c''est sa fête je vais fêter ça très fort pour que vous soyez quittes toi et moi. En attendant joyeuse fête, mon humain préféré, dont le saint patron veille apparemment sur toi.
Avec recherches théologiques approfondies et réciprocité planifiée, — {prenom}, ton animal en attente du 16 août 🙏$$,'humorous',true,false,'nameday','chien','from'),

(null,'Ce matin j''ai senti que c''était un jour spécial.',$$Ce matin j''ai senti que c''était un jour spécial.
Pas à cause du calendrier. Parce que t''avais une énergie différente. Une façon de te préparer. Un sourire anticipé. Je capte ces choses-là. Je suis un expert de toi. Joyeuse fête, mon humain préféré, dont je lis les humeurs avant même que tu te lèves.
Avec expertise émotionnelle certifiée et nez infaillible, — {prenom}, ton animal baromètre de tes journées depuis le premier jour 🌡️$$,'humorous',true,false,'nameday','chien','from'),

(null,'J''ai voulu te préparer quelque chose de spécial pour ta fête.',$$J''ai voulu te préparer quelque chose de spécial pour ta fête.
J''ai trouvé une chaussette. Propre cette fois. Enfin presque. Elle avait une petite odeur mais c''est ce qui lui donnait du caractère. Je l''ai apportée avec toute la cérémonie possible. T''as fait une tête. Puis t''as quand même souri. C''est ça le vrai cadeau. Ma façon de donner. Joyeuse fête, mon humain préféré, destinataire de mes offrandes les plus sincères.
Avec générosité textile et intention irréprochable, — {prenom}, ton animal aux cadeaux signature 🧦$$,'humorous',true,false,'nameday','chien','from'),

(null,'Ta fête c''est pas pareil que ton anniversaire mais c''est quand même une bonne excuse.',$$Ta fête c''est pas pareil que ton anniversaire mais c''est quand même une bonne excuse.
Une bonne excuse pour rester collé contre toi toute la journée. Pour réclamer plus de caresses que d''habitude. Pour faire des yeux particulièrement convaincants au moment des repas. T''aurais du mal à dire non un jour de fête. C''est tactique. C''est calculé. C''est moi. Joyeuse fête, mon humain préféré, dont les jours spéciaux sont mes meilleurs jours.
Avec stratégie affective rodée et timing impeccable, — {prenom}, ton animal aux opportunités bien saisies 🎯$$,'humorous',true,false,'nameday','chien','from'),

(null,'Les humains ont deux jours dans l''année où ils sont célébrés. Moi zéro.',$$Les humains ont deux jours dans l''année où ils sont célébrés. Moi zéro.
Enfin officiellement zéro. Parce que moi je célèbre chaque jour comme si c''était ma fête. Le réveil. La promenade. Le repas. Le canapé. Le retour à la maison. Chaque moment est une fête pour moi. Peut-être que c''est ça la vraie leçon. Joyeuse fête quand même, mon humain préféré, qui mérite ses deux jours par an.
Avec philosophie du quotidien et sagesse canine offerte gratuitement, — {prenom}, ton animal en fête permanente 🥳$$,'humorous',true,false,'nameday','chien','from'),

(null,'J''ai essayé de chanter quelque chose pour ta fête.',$$J''ai essayé de chanter quelque chose pour ta fête.
C''est sorti comme un aboiement long et modulé à 6h47 du matin. Les voisins ont tapé au mur. Tu t''es réveillé en sursaut. T''as pas eu l''air de reconnaître la mélodie. C''était pourtant clairement une sérénade. Joyeuse fête, mon humain préféré, dont je perfectionne le répertoire musical chaque année.
Avec talent vocal indéniable et public encore non converti, — {prenom}, ton animal artiste incompris du matin 🎵$$,'humorous',true,false,'nameday','chien','from'),

(null,'On m''a expliqué que ta fête c''est lié à un calendrier avec des saints dedans.',$$On m''a expliqué que ta fête c''est lié à un calendrier avec des saints dedans.
J''ai regardé le calendrier. Y''a un saint pour presque chaque jour. Ce qui veut dire que presque chaque jour quelqu''un fait la fête quelque part. Ce qui veut dire que presque chaque jour est une bonne raison de sauter partout et de réclamer des croquettes supplémentaires. Merci les saints. Joyeuse fête, mon humain préféré, dont la religion est très pratique pour moi.
Avec interprétation théologique libre et applications concrètes immédiates, — {prenom}, ton animal très attaché au calendrier liturgique 📅$$,'humorous',true,false,'nameday','chien','from'),

(null,'T''as reçu des messages toute la journée. Ton téléphone n''arrêtait pas.',$$T''as reçu des messages toute la journée. Ton téléphone n''arrêtait pas.
Buzz. Buzz. Buzz. J''ai essayé d''aboyer plus fort que lui. J''ai perdu. Puis j''ai compris que tous ces messages c''était pour toi. Que les gens pensaient à toi. Que t''étais quelqu''un d''important pour plein de monde. Je le savais déjà. Joyeuse fête, mon humain préféré, star du jour que je côtoie au quotidien.
Avec fierté d''être à tes côtés en toutes circonstances, — {prenom}, ton animal plus proche de toi que n''importe quel contact dans ton téléphone 📱$$,'humorous',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai décidé d''être particulièrement sage aujourd''hui.',$$Pour ta fête j''ai décidé d''être particulièrement sage aujourd''hui.
J''ai pas touché au canapé. J''ai pas suivi le chat du voisin. J''ai pas reniflé le sac de la dame qui est venue. J''ai même attendu sagement pendant le repas sans poser la tête sur la table. Une seule fois. Brièvement. Mais je l''ai retirée. Ça compte. Joyeuse fête, mon humain préféré, pour qui je me surpasse une fois par an.
Avec effort surhumain et bilan globalement positif, — {prenom}, ton animal en version premium pour l''occasion 🏅$$,'humorous',true,false,'nameday','chien','from'),

(null,'Y''a un truc que je comprends pas avec les fêtes des prénoms.',$$Y''a un truc que je comprends pas avec les fêtes des prénoms.
Pourquoi c''est le prénom qui fête et pas la personne ? Ton prénom a rien fait de spécial que je sache. C''est toi qui fais des choses. C''est toi qui me nourris. C''est toi qui ouvres la porte. Ton prénom il reste là dans ta tête à rien faire. Joyeuse fête quand même, mon humain préféré, et joyeuse fête aussi à ton prénom par acquit de conscience.
Avec questionnement philosophique sincère et double dédicace par précaution, — {prenom}, ton animal rigoureux dans ses hommages 🤔$$,'humorous',true,false,'nameday','chien','from'),

(null,'Ce soir y''avait du monde chez toi pour ta fête.',$$Ce soir y''avait du monde chez toi pour ta fête.
Des gens que je connaissais. Des gens que je connaissais pas. J''ai accueilli tout le monde avec la même énergie. Les habitués ont eu droit à mes pattes sur les épaules. Les nouveaux ont eu droit à un audit olfactif complet. C''est mon protocole d''accueil. Joyeuse fête, mon humain préféré, dont les soirées ont toujours un agent de sécurité attitré.
Avec sélection des invités par l''odorat et bilan sécuritaire satisfaisant, — {prenom}, ton animal videur de charme 🔐$$,'humorous',true,false,'nameday','chien','from'),

(null,'J''ai cherché ce qu''on offre pour une fête du prénom.',$$J''ai cherché ce qu''on offre pour une fête du prénom.
Internet dit des fleurs. Des chocolats. Un repas. Moi j''ai rien de tout ça. Mais j''ai quelque chose que personne d''autre peut t''offrir. Ma présence totale. Mon regard tourné vers toi en permanence. Mon incapacité physique à m''intéresser à autre chose quand t''es dans la pièce. C''est pas des fleurs. C''est mieux. Joyeuse fête, mon humain préféré.
Avec cadeau immatériel et valeur inestimable, — {prenom}, ton animal le plus dévoué qui soit 🌸$$,'humorous',true,false,'nameday','chien','from'),

(null,'Ta fête tombe un jour de semaine cette année.',$$Ta fête tombe un jour de semaine cette année.
T''as quand même l''air de bien le vivre. Même un mardi ordinaire avec le travail le lendemain tu trouves le moyen de sourire. C''est ce que j''aime chez toi. Cette capacité à trouver une raison d''être bien. Moi je fais pareil chaque matin quand tu ouvres la porte de la chambre. On est pareils toi et moi. Joyeuse fête, mon humain préféré, expert en joie du quotidien.
Avec reconnaissance pour ce trait de caractère précieux, — {prenom}, ton animal qui a appris la joie à tes côtés 🌅$$,'humorous',true,false,'nameday','chien','from'),

(null,'J''ai fait quelque chose sur le paillasson d''entrée ce matin.',$$J''ai fait quelque chose sur le paillasson d''entrée ce matin.
C''était pas intentionnel. Enfin si, un peu. Mais c''était pas le bon moment je sais. Sauf que la nature a ses propres horaires et aujourd''hui la nature a décidé que c''était sur le paillasson. Considère ça comme une décoration de fête organique et personnalisée. Joyeuse fête, mon humain préféré, dont le seuil est désormais marqué à mon nom.
Avec timing perfectible et symbolique territoriale forte, — {prenom}, ton animal qui marque les grandes occasions à sa façon 🎨$$,'humorous',true,false,'nameday','chien','from'),

(null,'Aujourd''hui quelqu''un t''a apporté des fleurs.',$$Aujourd''hui quelqu''un t''a apporté des fleurs.
Des vraies. Dans du papier. Qui sentaient fort. J''ai reniflé le bouquet pendant quatre minutes complètes sous ton regard de plus en plus inquiet. J''ai conclu que c''était comestible. T''as éloigné les fleurs. J''ai été vexé. On a quand même passé une belle soirée tous les deux après. Joyeuse fête, mon humain préféré, dont les cadeaux m''intéressent autant que toi.
Avec expertise botanique en développement et vexation de courte durée, — {prenom}, ton animal critique floral non sollicité 🌹$$,'touching',true,false,'nameday','chien','from'),

(null,'Pour ta fête j''ai décidé de pas mâcher tes affaires aujourd''hui.',$$Pour ta fête j''ai décidé de pas mâcher tes affaires aujourd''hui.
La télécommande est intacte. Le coin du canapé aussi. Tes chaussures sont exactement là où tu les as laissées. C''est mon cadeau. Invisible. Silencieux. Mais réel. Le cadeau de ce qui n''a pas été détruit. Tu peux pas me remercier parce que tu sais pas ce que j''aurais pu faire. Mais moi je sais. Joyeuse fête, mon humain préféré.
Avec retenue héroïque et cadeau négatif d''une valeur inestimable, — {prenom}, ton animal qui te protège de lui-même 🛡️$$,'humorous',true,false,'nameday','chien','from'),

(null,'Ce soir quand tout le monde est parti et que t''es venu t''asseoir sur le canapé j''ai posé ma tête sur tes genoux.',$$Ce soir quand tout le monde est parti et que t''es venu t''asseoir sur le canapé j''ai posé ma tête sur tes genoux.
Pas pour réclamer quelque chose. Pas parce que j''avais froid. Juste parce que c''était ta fête et que je voulais que tu saches que moi aussi je savais que c''était un jour spécial. À ma façon. Sans mots. Sans carte. Sans bouquet qui sent fort. Juste moi. Et toi. Et ce silence qui dit tout. Joyeuse fête, mon humain préféré.
Avec tendresse absolue et économie de mots assumée, — {prenom}, ton animal pour tous les jours spéciaux et les autres aussi ❤️$$,'touching',true,false,'nameday','chien','from')

on conflict do nothing;
